import Image from "next/image";
import Link from "next/link";

export default function Games() {
  return (
    <div className="flex flex-col gap-8 py-10" data-theme="theme-games">
      {/* Header */}
      <div className="text-center">
        <h1 className="text-4xl font-bold mb-4 text-accent">Games</h1>
        <p className="text-xl">Jogos que evangelizam e divertem.</p>
      </div>

      {/* Featured Game */}
      <div className="card lg:card-side bg-base-100 border-4 border-black shadow-[8px_8px_0_0_rgba(0,0,0,1)] rounded-none">
        <figure className="lg:w-1/3 bg-accent/10 p-8 flex items-center justify-center border-r-4 border-black">
             <div className="relative w-48 h-48">
                <Image
                    src="/logos/pixel-eucaristico---games.png"
                    alt="Games Logo"
                    fill
                    className="object-contain"
                />
            </div>
        </figure>
        <div className="card-body">
          <h2 className="card-title text-2xl mb-4">História do Santo Carlos Acutis</h2>
          <div className="badge badge-accent badge-outline rounded-none mb-4">Em Pesquisa</div>
          <p className="mb-4">
            Este projeto está em fase de pesquisa dos livros e referências para poder criar o GDD (Game Design Document) do projeto.
            Em breve, uma aventura emocionante sobre a vida do padroeiro da internet.
          </p>
          <div className="card-actions justify-end">
            <button className="btn btn-accent border-2 border-black shadow-[4px_4px_0_0_rgba(0,0,0,1)] rounded-none" disabled>
              Em Breve
            </button>
          </div>
        </div>
      </div>

      {/* Back Button */}
      <div className="text-center mt-8">
        <Link href="/" className="btn btn-ghost hover:bg-transparent hover:underline">
          ← Voltar para Home
        </Link>
      </div>
    </div>
  );
}
